import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";
import Footer from "../components/Footer";

export default function LabourDashboard() {

  const user = JSON.parse(localStorage.getItem("user"));

  const [jobs, setJobs] = useState([]);

  const [price, setPrice] = useState("");
  const [preferredTime, setPreferredTime] = useState("");

  useEffect(() => {

    axios
      .get(`http://localhost:5000/api/jobs/labour/${user._id}`)
      .then(res => setJobs(res.data));

  }, []);

  const acceptJob = async (id) => {

    await axios.put(
      `http://localhost:5000/api/jobs/accept/${id}`,
      {
        labourPrice: price,
        labourPreferredTime: preferredTime
      }
    );

    window.location.reload();
  };

  const rejectJob = async (id) => {

    await axios.put(
      `http://localhost:5000/api/jobs/reject/${id}`
    );

    window.location.reload();
  };

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <h1 style={styles.heading}>
          Job Requests
        </h1>

        <div style={styles.grid}>

          {jobs.map(job => (

            <div key={job._id} style={styles.card}>

              <h2>{job.customerName}</h2>

              <p>
                <strong>Work:</strong> {job.workType}
              </p>

              <p>
                <strong>Date:</strong> {job.customerDate}
              </p>

              <p>
                <strong>Customer Time:</strong>
                {job.customerTime}
              </p>

              <p>
                <strong>Status:</strong>
                {job.labourStatus}
              </p>

              {job.labourStatus === "pending" && (

                <>
                  <input
                    style={styles.input}
                    placeholder="Your Preferred Time"
                    onChange={(e) =>
                      setPreferredTime(e.target.value)
                    }
                  />

                  <input
                    style={styles.input}
                    placeholder="Enter Price"
                    onChange={(e) =>
                      setPrice(e.target.value)
                    }
                  />

                  <div style={styles.btnRow}>

                    <button
                      style={styles.acceptBtn}
                      onClick={() => acceptJob(job._id)}
                    >
                      Accept
                    </button>

                    <button
                      style={styles.rejectBtn}
                      onClick={() => rejectJob(job._id)}
                    >
                      Reject
                    </button>

                  </div>
                </>
              )}

            </div>
          ))}

        </div>

      </div>

      <Footer />

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px"
  },

  heading: {
    fontSize: "40px",
    marginBottom: "30px"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(320px,1fr))",
    gap: "20px"
  },

  card: {
    background: "white",
    padding: "25px",
    borderRadius: "18px",
    boxShadow: "0 8px 20px rgba(0,0,0,0.08)"
  },

  input: {
    width: "100%",
    padding: "12px",
    marginTop: "15px",
    borderRadius: "10px",
    border: "1px solid #ddd"
  },

  btnRow: {
    display: "flex",
    gap: "15px",
    marginTop: "20px"
  },

  acceptBtn: {
    flex: 1,
    background: "#22c55e",
    color: "white",
    border: "none",
    padding: "12px",
    borderRadius: "10px"
  },

  rejectBtn: {
    flex: 1,
    background: "#ef4444",
    color: "white",
    border: "none",
    padding: "12px",
    borderRadius: "10px"
  }
};
